/**
 * Interactive paper corpus table for concepts/paper-corpus-browser.md
 * Data: ../javascripts/papers_corpus.json (generated by scripts/generate_papers_indexes.py)
 */
(function () {
  "use strict";

  function esc(s) {
    const d = document.createElement("div");
    d.textContent = s == null ? "" : String(s);
    return d.innerHTML;
  }

  function domainLabel(d) {
    if (!d || typeof d !== "string") return "—";
    return d.replace(/^domain:/, "");
  }

  function axisLabel(x) {
    if (!x || typeof x !== "string") return "—";
    const i = x.indexOf(":");
    return i >= 0 ? x.slice(i + 1) : x;
  }

  function themeHref(slug) {
    return "../concepts/" + slug + ".md";
  }

  function sortPapers(papers, key) {
    const copy = papers.slice();
    switch (key) {
      case "year-asc":
        copy.sort((a, b) => (a.year || 0) - (b.year || 0) || a.title.localeCompare(b.title));
        break;
      case "title-za":
        copy.sort((a, b) => b.title.localeCompare(a.title));
        break;
      case "title-az":
        copy.sort((a, b) => a.title.localeCompare(b.title));
        break;
      case "domain-az":
        copy.sort((a, b) => a.domain.localeCompare(b.domain) || a.title.localeCompare(b.title));
        break;
      case "slug-az":
        copy.sort((a, b) => a.slug.localeCompare(b.slug));
        break;
      case "year-desc":
      default:
        copy.sort((a, b) => (b.year || 0) - (a.year || 0) || a.title.localeCompare(b.title));
    }
    return copy;
  }

  function filterPapers(papers, q, year, domain, theme, groupOnly, confidence) {
    const needle = (q || "").trim().toLowerCase();
    return papers.filter(function (p) {
      if (year !== "" && String(p.year || 0) !== year) return false;
      if (domain !== "" && p.domain !== domain) return false;
      if (theme !== "") {
        const th = p.themes || [];
        if (th.indexOf(theme) === -1) return false;
      }
      if (groupOnly && !p.group) return false;
      if (confidence !== "" && p.confidence !== confidence) return false;
      if (!needle) return true;
      const hay = (
        p.title +
        " " +
        p.slug +
        " " +
        (p.venue || "") +
        " " +
        (p.tags || []).join(" ") +
        " " +
        (p.task || "") +
        " " +
        (p.method || "")
      ).toLowerCase();
      return hay.indexOf(needle) !== -1;
    });
  }

  function render(root, papers, total) {
    const tbody = root.querySelector(".pc-tbody");
    if (!tbody) return;
    let html = "";
    for (let i = 0; i < papers.length; i++) {
      const p = papers[i];
      const y = p.year && p.year > 0 ? String(p.year) : "—";
      const themes = p.themes || [];
      let themeCell = "—";
      if (themes.length) {
        themeCell = themes
          .map(function (t) {
            return (
              '<a href="' +
              esc(themeHref(t)) +
              '">' +
              esc(t.replace(/^theme-/, "")) +
              "</a>"
            );
          })
          .join(", ");
      }
      const grp = p.group ? "yes" : "—";
      html +=
        "<tr>" +
        "<td>" +
        esc(y) +
        "</td>" +
        "<td><a href=\"../papers/" +
        esc(p.slug) +
        '.md">' +
        esc(p.title) +
        "</a></td>" +
        "<td>" +
        esc(domainLabel(p.domain)) +
        "</td>" +
        "<td>" +
        esc(axisLabel(p.method)) +
        "</td>" +
        "<td>" +
        themeCell +
        "</td>" +
        "<td>" +
        esc(p.confidence || "—") +
        "</td>" +
        "<td>" +
        grp +
        "</td>" +
        "<td><code>" +
        esc(p.slug) +
        "</code></td>" +
        "</tr>";
    }
    tbody.innerHTML = html;
    const countEl = root.querySelector(".pc-count");
    if (countEl) {
      countEl.textContent =
        "Showing " + papers.length + " of " + total + " papers (filters apply).";
    }
  }

  function uniqYears(papers) {
    const s = {};
    for (let i = 0; i < papers.length; i++) {
      const y = papers[i].year;
      if (y && y > 0) s[y] = true;
    }
    return Object.keys(s)
      .map(Number)
      .sort(function (a, b) {
        return b - a;
      });
  }

  function uniqDomains(papers) {
    const s = {};
    for (let i = 0; i < papers.length; i++) s[papers[i].domain] = true;
    return Object.keys(s).sort();
  }

  function uniqThemes(papers) {
    const s = {};
    for (let i = 0; i < papers.length; i++) {
      const th = papers[i].themes || [];
      for (let j = 0; j < th.length; j++) s[th[j]] = true;
    }
    return Object.keys(s).sort();
  }

  function init() {
    const root = document.getElementById("paper-corpus-root");
    if (!root) return;

    fetch(new URL("../javascripts/papers_corpus.json", window.location.href).href)
      .then(function (r) {
        if (!r.ok) throw new Error("HTTP " + r.status);
        return r.json();
      })
      .then(function (data) {
        const papers = data.papers || [];
        const total = papers.length;
        const years = uniqYears(papers);
        const domains = uniqDomains(papers);
        const themes = uniqThemes(papers);

        const ySel = root.querySelector(".pc-year");
        const dSel = root.querySelector(".pc-domain");
        const tSel = root.querySelector(".pc-theme");
        const sSel = root.querySelector(".pc-sort");
        const gCb = root.querySelector(".pc-group");
        const cSel = root.querySelector(".pc-confidence");
        const qIn = root.querySelector(".pc-search");

        function opt(sel, value, label) {
          const o = document.createElement("option");
          o.value = value;
          o.textContent = label;
          sel.appendChild(o);
        }

        if (ySel && ySel.options.length === 0) {
          opt(ySel, "", "All years");
          for (let i = 0; i < years.length; i++) opt(ySel, String(years[i]), String(years[i]));
        }
        if (dSel && dSel.options.length === 0) {
          opt(dSel, "", "All domains");
          for (let i = 0; i < domains.length; i++)
            opt(dSel, domains[i], domainLabel(domains[i]));
        }
        if (tSel && tSel.options.length === 0) {
          opt(tSel, "", "Any theme link");
          for (let i = 0; i < themes.length; i++)
            opt(tSel, themes[i], themes[i].replace(/^theme-/, ""));
        }
        if (cSel && cSel.options.length === 0) {
          opt(cSel, "", "All confidence");
          opt(cSel, "high", "high");
          opt(cSel, "med", "med");
          opt(cSel, "low", "low");
        }

        function refresh() {
          const q = qIn ? qIn.value : "";
          const year = ySel ? ySel.value : "";
          const domain = dSel ? dSel.value : "";
          const theme = tSel ? tSel.value : "";
          const sort = sSel ? sSel.value : "year-desc";
          const groupOnly = gCb && gCb.checked;
          const conf = cSel ? cSel.value : "";
          let list = filterPapers(papers, q, year, domain, theme, groupOnly, conf);
          list = sortPapers(list, sort);
          render(root, list, total);
        }

        if (qIn) qIn.addEventListener("input", refresh);
        if (ySel) ySel.addEventListener("change", refresh);
        if (dSel) dSel.addEventListener("change", refresh);
        if (tSel) tSel.addEventListener("change", refresh);
        if (sSel) sSel.addEventListener("change", refresh);
        if (gCb) gCb.addEventListener("change", refresh);
        if (cSel) cSel.addEventListener("change", refresh);

        refresh();
      })
      .catch(function (e) {
        root.innerHTML =
          '<p class="admonition failure">Could not load <code>papers_corpus.json</code>. Run <code>python3 scripts/generate_papers_indexes.py</code> after adding papers. (' +
          esc(e.message) +
          ")</p>";
      });
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", init);
  } else {
    init();
  }
})();
